4		"errors"
5		"fmt"
6		"net"
7		"net/netip"
8		"net/url"
9		"strings"
10		"time"
11	
12		"github.com/7mind/wanbond/internal/dnsresolve"
13	)
14	
15	// DNSResolverMode selects the transport dns.resolver picks.
16	type DNSResolverMode string
17	
18	const (
19		// DNSResolverSystem uses the OS stub resolver (dnsresolve.SystemResolver).
20		// It is the default when [dns] is omitted or resolver is left empty.
21		DNSResolverSystem DNSResolverMode = "system"
22		// DNSResolverDoH uses DNS-over-HTTPS (dnsresolve.DoHResolver).
23		DNSResolverDoH DNSResolverMode = "doh"
24		// DNSResolverDoT uses DNS-over-TLS (dnsresolve.DoTResolver).
25		DNSResolverDoT DNSResolverMode = "dot"
26	)
27	
28	func (m DNSResolverMode) valid() bool {
29		return m == DNSResolverSystem || m == DNSResolverDoH || m == DNSResolverDoT
30	}
31	
32	// Default cadence/timeout for the [dns] block (Q31): the poll interval sits on
33	// the reconcile-cadence scale — frequent enough that a DDNS repoint is picked
34	// up promptly, far coarser than the sub-second deferred-path/probe loops
35	// (bind.DefaultReconcileInterval = 1s) since re-resolution costs a real
36	// network round trip to the configured resolver and re-resolving too eagerly
37	// would needlessly load it. The per-lookup timeout mirrors dnsresolve's own
38	// internal DoH/DoT bounds (5s).
39	const (
40		defaultDNSPollInterval = 30 * time.Second
41		defaultDNSTimeout      = 5 * time.Second
42	)
43	
44	// dotDefaultPort mirrors dnsresolve's unexported dotPort: DNS-over-TLS's
45	// IANA-assigned port (RFC 7858 §3), and the ONLY port dnsresolve.NewDoTResolver
46	// ever dials (it appends this fixed port itself). An explicit port in
47	// dot_server must match it, so a mistyped non-standard port fails fast at
48	// config load rather than being silently ignored when the resolver is built.
49	const dotDefaultPort = "853"
50	
51	// DNS selects and tunes the resolver transport used for opted-in hostname
52	// peer-endpoint re-resolution (Q29/Q31). An ABSENT [dns] block is INERT: it
53	// defaults to the system resolver, and resolution only happens at all when a
54	// peer separately opts in with its own `dns = true` flag (Peer.DNS) —
55	// [dns] merely selects which transport that opt-in uses, it is never a gate
56	// by itself.
57	type DNS struct {
58		// Resolver selects the transport: "system" (default), "doh", or "dot".
59		Resolver DNSResolverMode `toml:"resolver"`
60		// DoHURL is the DNS-over-HTTPS query endpoint (an https:// URL). Required
61		// iff resolver = "doh"; rejected (must stay empty) under any other
62		// resolver.
63		DoHURL string `toml:"doh_url"`
64		// DoTServer is the DNS-over-TLS server: a bare host, or "host:port" where
65		// port must be dotDefaultPort (853) — dnsresolve.NewDoTResolver always
66		// dials that port itself, so any other explicit port cannot be honored.
67		// Required iff resolver = "dot"; rejected (must stay empty) under any
68		// other resolver.
69		DoTServer string `toml:"dot_server"`
70		// BootstrapIP is the literal IP address wanbond dials the DoH/DoT server
71		// on when doh_url/dot_server names it by HOSTNAME rather than IP literal
72		// (the chicken-and-egg BOOTSTRAP-IP invariant, Q33): resolving the
73		// private resolver's own name would itself require a DNS lookup — via
74		// the system resolver [dns] exists to avoid — defeating the point of
75		// configuring a private resolver. Required iff the doh_url/dot_server
76		// host is a hostname; ignored when it is already an IP literal.
77		BootstrapIP string `toml:"bootstrap_ip"`
78		// PollInterval is the re-resolution cadence for an opted-in hostname peer
79		// endpoint (Q31), parsed from PollIntervalRaw in applyDefaults. Defaults to
80		// defaultDNSPollInterval when PollIntervalRaw is left empty; must be > 0
81		// after defaulting.
82		PollInterval time.Duration `toml:"-"`
83		// PollIntervalRaw is the TOML Go-duration string form of PollInterval,
84		// e.g. "30s". Mirrors Path.LinkRTTRaw: go-toml/v2 cannot decode a TOML
85		// string directly into a time.Duration field, so the raw string is parsed
86		// via time.ParseDuration in applyDefaults.
87		PollIntervalRaw string `toml:"poll_interval"`
88		// Timeout bounds a single resolver lookup, parsed from TimeoutRaw in
89		// applyDefaults. Defaults to defaultDNSTimeout when TimeoutRaw is left
90		// empty; must be > 0 after defaulting.
91		Timeout time.Duration `toml:"-"`
92		// TimeoutRaw is the TOML Go-duration string form of Timeout, e.g. "5s".
93		TimeoutRaw string `toml:"timeout"`
94	}
95	
96	// applyDefaults fills the resolver mode and cadence/timeout knobs left at
97	// their zero value, so a minimal or absent [dns] block resolves to explicit,
98	// usable settings — an absent block still ends up as the system resolver
99	// with the standard cadence/timeout, per the type's zero-value contract.
100	// PollIntervalRaw/TimeoutRaw are parsed here (mirroring Path's *Raw-field
101	// normalize step for LinkRTTRaw); an unparseable duration string is reported
102	// immediately.
103	func (d *DNS) applyDefaults() error {
104		if d.Resolver == "" {
105			d.Resolver = DNSResolverSystem
106		}
107		if d.PollIntervalRaw == "" {
108			d.PollInterval = defaultDNSPollInterval
109		} else {
110			v, err := time.ParseDuration(d.PollIntervalRaw)
111			if err != nil {
112				return fmt.Errorf("dns.poll_interval: invalid duration %q: %w", d.PollIntervalRaw, err)
113			}
114			d.PollInterval = v
115		}
116		if d.TimeoutRaw == "" {
117			d.Timeout = defaultDNSTimeout
118		} else {
119			v, err := time.ParseDuration(d.TimeoutRaw)
120			if err != nil {
121				return fmt.Errorf("dns.timeout: invalid duration %q: %w", d.TimeoutRaw, err)
122			}
123			d.Timeout = v
124		}
125		return nil
126	}
127	
128	// validate enforces the [dns] block invariants: a resolver-mode-appropriate
129	// set of required fields, no stray fields left over from a different mode,
130	// positive cadence/timeout, and the BOOTSTRAP-IP invariant for a hostname-form
131	// doh_url/dot_server. Runs after applyDefaults (mirroring Amnezia/FEC/
132	// SchedulerConfig), so Resolver/PollInterval/Timeout are already defaulted.
133	func (d DNS) validate() error {
134		if !d.Resolver.valid() {
135			return fmt.Errorf("dns.resolver must be %q, %q or %q, got %q", DNSResolverSystem, DNSResolverDoH, DNSResolverDoT, d.Resolver)
136		}
137		if d.PollInterval <= 0 {
138			return fmt.Errorf("dns.poll_interval must be > 0, got %s", d.PollInterval)
139		}
140		if d.Timeout <= 0 {
141			return fmt.Errorf("dns.timeout must be > 0, got %s", d.Timeout)
142		}
143	
144		switch d.Resolver {
145		case DNSResolverSystem:
146			if d.DoHURL != "" {
147				return errors.New("dns.doh_url is only meaningful when dns.resolver = \"doh\"")
148			}
149			if d.DoTServer != "" {
150				return errors.New("dns.dot_server is only meaningful when dns.resolver = \"dot\"")
151			}
152			if d.BootstrapIP != "" {
153				return errors.New("dns.bootstrap_ip is only meaningful when dns.resolver is \"doh\" or \"dot\"")
154			}
155			return nil
156		case DNSResolverDoH:
157			if d.DoTServer != "" {
158				return errors.New("dns.dot_server is not meaningful when dns.resolver = \"doh\"")
159			}
160			if d.DoHURL == "" {
161				return errors.New("dns.doh_url is required when dns.resolver = \"doh\"")
162			}
163			host, err := dohURLHost(d.DoHURL)
164			if err != nil {
165				return fmt.Errorf("dns.doh_url: %w", err)
166			}
167			return d.requireBootstrapForHost(host)
168		case DNSResolverDoT:
169			if d.DoHURL != "" {
170				return errors.New("dns.doh_url is not meaningful when dns.resolver = \"dot\"")
171			}
172			if d.DoTServer == "" {
173				return errors.New("dns.dot_server is required when dns.resolver = \"dot\"")
174			}
175			host, err := dotServerHost(d.DoTServer)
176			if err != nil {
177				return fmt.Errorf("dns.dot_server: %w", err)
178			}
179			return d.requireBootstrapForHost(host)
180		default:
181			// Unreachable: d.Resolver.valid() above already rejected anything else.
182			return fmt.Errorf("dns.resolver: unhandled mode %q", d.Resolver)
183		}
184	}
185	
186	// requireBootstrapForHost enforces the BOOTSTRAP-IP invariant for the given
187	// (already-extracted) doh_url/dot_server host: an IP literal needs no
188	// bootstrap; a hostname requires an explicit, valid bootstrap_ip.
189	func (d DNS) requireBootstrapForHost(host string) error {
190		if _, err := netip.ParseAddr(host); err == nil {
191			return nil
192		}
193		if d.BootstrapIP == "" {
194			return fmt.Errorf("hostname %q requires dns.bootstrap_ip: the resolver's own address must be reachable without a DNS lookup (a plaintext lookup of the private resolver's own name would defeat the point of configuring one)", host)
195		}
196		if _, err := netip.ParseAddr(d.BootstrapIP); err != nil {
197			return fmt.Errorf("dns.bootstrap_ip %q is not a valid IP literal: %w", d.BootstrapIP, err)
198		}
199		return nil
200	}
201	
202	// dohURLHost extracts and validates the host component of a doh_url: it must
203	// be a well-formed https:// URL with a non-empty host.
204	func dohURLHost(rawURL string) (string, error) {
205		u, err := url.Parse(rawURL)
206		if err != nil {
207			return "", fmt.Errorf("invalid URL %q: %w", rawURL, err)
208		}
209		if u.Scheme != "https" {
210			return "", fmt.Errorf("must use https, got scheme %q in %q", u.Scheme, rawURL)
211		}
212		host := u.Hostname()
213		if host == "" {
214			return "", fmt.Errorf("missing host in %q", rawURL)
215		}
216		return host, nil
217	}
218	
219	// dotServerHost extracts and validates the host component of a dot_server: a
220	// bare host (hostname or IP literal, no port) is accepted as-is; a
221	// "host:port" form is split and requires port == dotDefaultPort, since
222	// dnsresolve.NewDoTResolver always dials that fixed port itself.
223	func dotServerHost(raw string) (string, error) {
224		if raw == "" {
225			return "", errors.New("empty")
226		}
227		// A bare IP literal (including an unbracketed IPv6 literal, which itself
228		// contains colons) has no port to split off.
229		if _, err := netip.ParseAddr(raw); err == nil {
230			return raw, nil
231		}
232		if !strings.Contains(raw, ":") {
233			return raw, nil // bare hostname, no port
234		}
235		host, port, err := net.SplitHostPort(raw)
236		if err != nil {
237			return "", fmt.Errorf("invalid dot_server %q: %w", raw, err)
238		}
239		if port != dotDefaultPort {
240			return "", fmt.Errorf("port %q must be %q (the IANA-assigned DNS-over-TLS port; dnsresolve always dials it)", port, dotDefaultPort)
241		}
242		return host, nil
243	}
244	
245	// NewResolver constructs the dnsresolve.Resolver implementation the
246	// (validated) [dns] block selects: dnsresolve.NewSystemResolver for the
247	// default/system mode, dnsresolve.NewDoHResolver/NewDoTResolver for doh/dot,
248	// or their *WithBootstrap variants when bootstrap_ip is set. Callers
249	// normally obtain a DNS value via config.Load, which already ran
250	// applyDefaults/validate; calling this on an un-validated DNS value surfaces
251	// whatever the underlying dnsresolve constructor rejects.
252	//
253	// bootstrap_ip (validated fail-fast, see requireBootstrapForHost) IS wired
254	// into the constructed resolver's dial target: when set, the resolver dials
255	// bootstrap_ip directly instead of resolving the configured hostname through
256	// the system dialer — the BOOTSTRAP-IP invariant (Q33) exists precisely to
257	// avoid that plaintext lookup of the private resolver's own name.
258	func (d DNS) NewResolver() (dnsresolve.Resolver, error) {
259		switch d.Resolver {
260		case DNSResolverDoH:
261			if d.BootstrapIP != "" {
262				return dnsresolve.NewDoHResolverWithBootstrap(d.DoHURL, d.BootstrapIP)
263			}
264			return dnsresolve.NewDoHResolver(d.DoHURL)
265		case DNSResolverDoT:
266			host, err := dotServerHost(d.DoTServer)
267			if err != nil {
268				return nil, fmt.Errorf("dns.dot_server: %w", err)
269			}
270			if d.BootstrapIP != "" {
271				return dnsresolve.NewDoTResolverWithBootstrap(host, d.BootstrapIP)
272			}
273			return dnsresolve.NewDoTResolver(host)
274		default:
275			return dnsresolve.NewSystemResolver(), nil
276		}
277	}
