78		// PollInterval is the re-resolution cadence for an opted-in hostname peer
79		// endpoint (Q31), parsed from PollIntervalRaw in applyDefaults. Defaults to
80		// defaultDNSPollInterval when PollIntervalRaw is left empty; must be > 0
81		// after defaulting.
82		PollInterval time.Duration `toml:"-"`
83		// PollIntervalRaw is the TOML Go-duration string form of PollInterval,
84		// e.g. "30s". Mirrors Path.LinkRTTRaw: go-toml/v2 cannot decode a TOML
85		// string directly into a time.Duration field, so the raw string is parsed
86		// via time.ParseDuration in applyDefaults.
87		PollIntervalRaw string `toml:"poll_interval"`
88		// Timeout bounds a single resolver lookup, parsed from TimeoutRaw in
89		// applyDefaults. Defaults to defaultDNSTimeout when TimeoutRaw is left
90		// empty; must be > 0 after defaulting.
91		Timeout time.Duration `toml:"-"`
92		// TimeoutRaw is the TOML Go-duration string form of Timeout, e.g. "5s".
93		TimeoutRaw string `toml:"timeout"`
94	}
95	
96	// applyDefaults fills the resolver mode and cadence/timeout knobs left at
97	// their zero value, so a minimal or absent [dns] block resolves to explicit,
98	// usable settings — an absent block still ends up as the system resolver
99	// with the standard cadence/timeout, per the type's zero-value contract.
100	// PollIntervalRaw/TimeoutRaw are parsed here (mirroring Path's *Raw-field
101	// normalize step for LinkRTTRaw); an unparseable duration string is reported
102	// immediately.
103	func (d *DNS) applyDefaults() error {
104		if d.Resolver == "" {
105			d.Resolver = DNSResolverSystem
106		}
107		if d.PollIntervalRaw == "" {
108			d.PollInterval = defaultDNSPollInterval
109		} else {
110			v, err := time.ParseDuration(d.PollIntervalRaw)
111			if err != nil {
112				return fmt.Errorf("dns.poll_interval: invalid duration %q: %w", d.PollIntervalRaw, err)
113			}
114			d.PollInterval = v
115		}
116		if d.TimeoutRaw == "" {
117			d.Timeout = defaultDNSTimeout
118		} else {
119			v, err := time.ParseDuration(d.TimeoutRaw)
120			if err != nil {
121				return fmt.Errorf("dns.timeout: invalid duration %q: %w", d.TimeoutRaw, err)
122			}
123			d.Timeout = v
124		}
125		return nil
126	}
127	
128	// validate enforces the [dns] block invariants: a resolver-mode-appropriate
129	// set of required fields, no stray fields left over from a different mode,
130	// positive cadence/timeout, and the BOOTSTRAP-IP invariant for a hostname-form
131	// doh_url/dot_server. Runs after applyDefaults (mirroring Amnezia/FEC/
132	// SchedulerConfig), so Resolver/PollInterval/Timeout are already defaulted.
133	func (d DNS) validate() error {
134		if !d.Resolver.valid() {
135			return fmt.Errorf("dns.resolver must be %q, %q or %q, got %q", DNSResolverSystem, DNSResolverDoH, DNSResolverDoT, d.Resolver)
136		}
137		if d.PollInterval <= 0 {
138			return fmt.Errorf("dns.poll_interval must be > 0, got %s", d.PollInterval)
139		}
140		if d.Timeout <= 0 {
141			return fmt.Errorf("dns.timeout must be > 0, got %s", d.Timeout)
142		}
143	
144		switch d.Resolver {
145		case DNSResolverSystem:
146			if d.DoHURL != "" {
147				return errors.New("dns.doh_url is only meaningful when dns.resolver = \"doh\"")
148			}
149			if d.DoTServer != "" {
150				return errors.New("dns.dot_server is only meaningful when dns.resolver = \"dot\"")
151			}
152			if d.BootstrapIP != "" {
153				return errors.New("dns.bootstrap_ip is only meaningful when dns.resolver is \"doh\" or \"dot\"")
154			}
155			return nil
